-- Create "notification_channel_test_proofs" table
CREATE TABLE "notification_channel_test_proofs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "kind" character varying NOT NULL,
  "status" character varying NOT NULL,
  "reason_code" character varying NOT NULL,
  "message" character varying NOT NULL,
  "content_kind" character varying NULL,
  "content_sha256" character varying NULL,
  "checked_at" timestamptz NOT NULL,
  "provider_message_id" character varying NULL,
  "provider_status" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "notification_channel_profile_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "notification_channel_test_proofs_notification_channel_profiles_" FOREIGN KEY ("notification_channel_profile_id") REFERENCES "notification_channel_profiles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "notificationchanneltestproof_notification_channel_profile_id_ch" to table: "notification_channel_test_proofs"
CREATE INDEX "notificationchanneltestproof_notification_channel_profile_id_ch" ON "notification_channel_test_proofs" ("notification_channel_profile_id", "checked_at");
-- Create index "notificationchanneltestproof_notification_channel_profile_id_co" to table: "notification_channel_test_proofs"
CREATE INDEX "notificationchanneltestproof_notification_channel_profile_id_co" ON "notification_channel_test_proofs" ("notification_channel_profile_id", "content_kind", "checked_at");
